'use client';

import * as React from 'react';
import * as RadioPrimitive from '@radix-ui/react-radio-group';

import { cn } from '@/lib/utils';
import './index.css';

const RadioGroup = React.forwardRef<
  React.ComponentRef<typeof RadioPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof RadioPrimitive.Root>
>(({ className, ...props }, ref) => (
  <RadioPrimitive.Root
    ref={ref}
    className={cn('jb-radio-group grid gap-3', className)}
    {...props}
  />
));
RadioGroup.displayName = RadioPrimitive.Root.displayName;

const RadioGroupItem = React.forwardRef<
  React.ComponentRef<typeof RadioPrimitive.Item>,
  React.ComponentPropsWithoutRef<typeof RadioPrimitive.Item>
>(({ className, children, ...props }, ref) => (
  <RadioPrimitive.Item
    ref={ref}
    className={cn(
      'jb-radio-item inline-flex size-5 shrink-0 items-center justify-center rounded-full border outline-none transition-[background-color,border-color,box-shadow] duration-150 ease-in-out disabled:pointer-events-none disabled:cursor-not-allowed',
      className,
    )}
    {...props}
  >
    {children}
    <RadioPrimitive.Indicator
      className={cn('jb-radio-indicator size-2.5 rounded-full')}
    />
  </RadioPrimitive.Item>
));
RadioGroupItem.displayName = RadioPrimitive.Item.displayName;

export { RadioGroup, RadioGroupItem };

.jb-radio-item {
  --jb-radio-bg: var(--jb-radio-unchecked-bg);
  --jb-radio-border: var(--jb-radio-unchecked-border);
  --jb-radio-bg-hover: var(--jb-radio-unchecked-bg-hover);
  --jb-radio-border-hover: var(--jb-radio-unchecked-border-hover);
  --jb-radio-bg-active: var(--jb-radio-unchecked-bg-active);
  --jb-radio-border-active: var(--jb-radio-unchecked-border-active);
  --jb-radio-ring: var(--jb-radio-unchecked-ring);
  --jb-radio-bg-invalid: var(--jb-radio-unchecked-bg-invalid);
  --jb-radio-border-invalid: var(--jb-radio-unchecked-border-invalid);
  --jb-radio-ring-invalid: var(--jb-radio-unchecked-ring-invalid);
  --jb-radio-bg-disabled: var(--jb-radio-unchecked-bg-disabled);
  --jb-radio-border-disabled: var(--jb-radio-unchecked-border-disabled);
  --jb-radio-indicator: var(--jb-radio-checked-indicator);
  --jb-radio-indicator-hover: var(--jb-radio-checked-indicator-hover);
  --jb-radio-indicator-active: var(--jb-radio-checked-indicator-active);
  --jb-radio-indicator-invalid: var(--jb-radio-checked-indicator-invalid);
  --jb-radio-indicator-disabled: var(--jb-radio-checked-indicator-disabled);

  border-color: var(--jb-radio-border);
  background: var(--jb-radio-bg);
}

.jb-radio-item[data-state='checked'] {
  --jb-radio-bg: var(--jb-radio-checked-bg);
  --jb-radio-border: var(--jb-radio-checked-border);
  --jb-radio-bg-hover: var(--jb-radio-checked-bg-hover);
  --jb-radio-border-hover: var(--jb-radio-checked-border-hover);
  --jb-radio-bg-active: var(--jb-radio-checked-bg-active);
  --jb-radio-border-active: var(--jb-radio-checked-border-active);
  --jb-radio-ring: var(--jb-radio-checked-ring);
  --jb-radio-bg-invalid: var(--jb-radio-checked-bg-invalid);
  --jb-radio-border-invalid: var(--jb-radio-checked-border-invalid);
  --jb-radio-ring-invalid: var(--jb-radio-checked-ring-invalid);
  --jb-radio-bg-disabled: var(--jb-radio-checked-bg-disabled);
  --jb-radio-border-disabled: var(--jb-radio-checked-border-disabled);
}

.jb-radio-item:hover:not(:disabled) {
  background: var(--jb-radio-bg-hover);
  border-color: var(--jb-radio-border-hover);
}

.jb-radio-item:active:not(:disabled) {
  background: var(--jb-radio-bg-active);
  border-color: var(--jb-radio-border-active);
}

.jb-radio-item:focus-visible {
  box-shadow: 0 0 0 2px var(--jb-radio-ring);
}

.jb-radio-item[aria-invalid='true'] {
  background: var(--jb-radio-bg-invalid);
  border-color: var(--jb-radio-border-invalid);
}

.jb-radio-item[aria-invalid='true']:focus-visible {
  box-shadow: 0 0 0 2px var(--jb-radio-ring-invalid);
}

.jb-radio-item:disabled {
  pointer-events: none;
  cursor: not-allowed;
  background: var(--jb-radio-bg-disabled);
  border-color: var(--jb-radio-border-disabled);
}

.jb-radio-indicator {
  background: var(--jb-radio-indicator);
}

.jb-radio-item:hover:not(:disabled) .jb-radio-indicator {
  background: var(--jb-radio-indicator-hover);
}

.jb-radio-item:active:not(:disabled) .jb-radio-indicator {
  background: var(--jb-radio-indicator-active);
}

.jb-radio-item[aria-invalid='true'] .jb-radio-indicator {
  background: var(--jb-radio-indicator-invalid);
}

.jb-radio-item:disabled .jb-radio-indicator {
  background: var(--jb-radio-indicator-disabled);
}
